import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './mentorDashboard.css';

function MentorDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [mentorData, setMentorData] = useState(null);
  const [students, setStudents] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);
  const [availabilitySlots, setAvailabilitySlots] = useState([]);
  const [mentorRequests, setMentorRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const user = JSON.parse(localStorage.getItem('user'));
        if (!user) {
          navigate('/');
          return;
        }

        const token = localStorage.getItem('token');

        // Fetch mentor data
        const res = await axios.get('http://localhost:5050/api/mentors/me', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setMentorData(res.data);

        // Fetch assigned students
        const studentsRes = await axios.get(`http://localhost:5050/api/students/mentor/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setStudents(studentsRes.data);

        // Fetch meetings
        const meetingsRes = await axios.get(`http://localhost:5050/api/meetings/mentor/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setMeetings(meetingsRes.data);

        // Fetch reports
        const reportsRes = await axios.get(`http://localhost:5050/api/reports/mentor/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setReports(reportsRes.data);

        // Fetch availability
        const availRes = await axios.get(`http://localhost:5050/api/availability/mentor/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setAvailabilitySlots(availRes.data);

        // Fetch mentor requests
        const requestsRes = await axios.get(`http://localhost:5050/api/mentor-requests/mentor/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setMentorRequests(requestsRes.data);

      } catch (error) {
        console.error("Error fetching data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [navigate]);

  const handleAcceptRequest = async (requestId) => {
    try {
      const token = localStorage.getItem('token');
      await axios.put(`http://localhost:5050/api/mentor-requests/${requestId}`, { status: 'accepted' }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      // Refresh requests
      const requestsRes = await axios.get(`http://localhost:5050/api/mentor-requests/mentor/${JSON.parse(localStorage.getItem('user')).id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMentorRequests(requestsRes.data);
    } catch (error) {
      console.error("Error accepting request:", error);
    }
  };

  const handleRejectRequest = async (requestId) => {
    try {
      const token = localStorage.getItem('token');
      await axios.put(`http://localhost:5050/api/mentor-requests/${requestId}`, { status: 'rejected' }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      // Refresh requests
      const requestsRes = await axios.get(`http://localhost:5050/api/mentor-requests/mentor/${JSON.parse(localStorage.getItem('user')).id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMentorRequests(requestsRes.data);
    } catch (error) {
      console.error("Error rejecting request:", error);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    navigate('/');
  };

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div className="dashboard">
      <header className="dashboard-header">
        <h1>Mentor Dashboard</h1>
        <button onClick={handleLogout} className="logout-btn">Logout</button>
      </header>

      <nav className="dashboard-nav">
        <button onClick={() => setActiveTab('dashboard')} className={activeTab === 'dashboard' ? 'active' : ''}>Dashboard</button>
        <button onClick={() => setActiveTab('students')} className={activeTab === 'students' ? 'active' : ''}>Students</button>
        <button onClick={() => setActiveTab('meetings')} className={activeTab === 'meetings' ? 'active' : ''}>Meetings</button>
        <button onClick={() => setActiveTab('reports')} className={activeTab === 'reports' ? 'active' : ''}>Reports</button>
        <button onClick={() => setActiveTab('requests')} className={activeTab === 'requests' ? 'active' : ''}>Requests</button>
        <button onClick={() => setActiveTab('availability')} className={activeTab === 'availability' ? 'active' : ''}>Availability</button>
      </nav>

      <div className="dashboard-content">
        {activeTab === 'dashboard' && (
          <div className="dashboard-overview">
            <h2>Welcome, {mentorData?.name}</h2>
            <p>Email: {mentorData?.email}</p>
            <p>Institution: {mentorData?.institution}</p>
            <p>Assigned Students: {students.length}</p>
          </div>
        )}

        {activeTab === 'students' && (
          <div className="students-section">
            <h2>Assigned Students</h2>
            <div className="students-list">
              {students.map(student => (
                <div key={student.id} className="student-card">
                  <h3>{student.name}</h3>
                  <p>Email: {student.email}</p>
                  <p>Institution: {student.institution}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'meetings' && (
          <div className="meetings-section">
            <h2>Meetings</h2>
            <div className="meetings-list">
              {meetings.map(meeting => (
                <div key={meeting.id} className="meeting-card">
                  <h3>{meeting.title}</h3>
                  <p><strong>Date:</strong> {new Date(meeting.date).toLocaleDateString()}</p>
                  <p><strong>Time:</strong> {meeting.time}</p>
                  <p><strong>Location:</strong> {meeting.location}</p>
                  <p><strong>Status:</strong> {meeting.status}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'reports' && (
          <div className="reports-section">
            <h2>Student Reports</h2>
            <div className="reports-list">
              {reports.map(report => (
                <div key={report.id} className="report-card">
                  <h3>{report.title}</h3>
                  <p><strong>Date:</strong> {new Date(report.date).toLocaleDateString()}</p>
                  <p><strong>Status:</strong> {report.status}</p>
                  {report.feedback && (
                    <p><strong>Feedback:</strong> {report.feedback}</p>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'requests' && (
          <div className="requests-section">
            <h2>Mentor Requests</h2>
            <div className="requests-list">
              {mentorRequests.map(request => (
                <div key={request.id} className="request-card">
                  <h3>Request from {request.studentName}</h3>
                  <p>Email: {request.studentEmail}</p>
                  <p>Message: {request.message}</p>
                  <p>Status: {request.status}</p>
                  {request.status === 'pending' && (
                    <div>
                      <button onClick={() => handleAcceptRequest(request.id)}>Accept</button>
                      <button onClick={() => handleRejectRequest(request.id)}>Reject</button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'availability' && (
          <div className="availability-section">
            <h2>My Availability</h2>
            <div className="slots-list">
              {availabilitySlots.map(slot => (
                <div key={slot.id} className="slot-card">
                  <h3>{slot.day}</h3>
                  <p><strong>Time:</strong> {slot.startTime} - {slot.endTime}</p>
                  <p><strong>Status:</strong> {slot.status}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default MentorDashboard;
